"""RAG Knowledge Base — Moroccan Comprehensive Awareness for YAQEEN"""
import re, json, unicodedata

class MoroccoRAG:
    RAW_STOP_WORDS = {"مغرب","مغربي","مغربية","مغربيات","في","على","من","الى","عن","مع","هو","هي","هم","كان"}

    def __init__(self):
        self.STOP_WORDS = {self._normalize(w) for w in self.RAW_STOP_WORDS}
        self.entries = self._build_db()

    def search(self, query, top_k=3):
        q = self._normalize(query)
        q_words = set(q.split())
        scored = []
        for e in self.entries:
            kw = e.get("kw", [])
            matched = 0
            for k in kw:
                k_norm = self._normalize(k)
                if k_norm in q_words and k_norm not in self.STOP_WORDS:
                    matched += 1
            if matched > 0:
                scored.append((matched, e))
        scored.sort(key=lambda x: -x[0])
        return [e for _, e in scored[:top_k]]

    def inject(self, query):
        results = self.search(query)
        if not results:
            return ""
        ctx = "\n\nالمعرفة المغربية:\n"
        for r in results:
            ctx += f"• {r['t']}: {r['c']}\n"
        return ctx

    @staticmethod
    def _normalize(t):
        # Arabic normalization
        t = t.lower()
        t = t.replace("\u0623", "\u0627")  # أ -> ا
        t = t.replace("\u0625", "\u0627")  # إ -> ا
        t = t.replace("\u0622", "\u0627")  # آ -> ا
        t = t.replace("\u0629", "\u0647")  # ة -> ه
        t = t.replace("\u0649", "\u064a")  # ى -> ي
        t = unicodedata.normalize("NFKD", t)
        t = re.sub(r"[\u064b-\u065f]", "", t)  # remove tashkeel
        t = re.sub(r"[^\w\s]", " ", t)
        t = re.sub(r"\s+", " ", t).strip()
        # strip "ال" prefix for matching
        words = []
        for w in t.split():
            if w.startswith("\u0627\u0644") and len(w) > 3:
                words.append(w[2:])
            words.append(w)
        return " ".join(words)

