            {"kw":["أمازيغ","أمازيغية","شلحة","تريفيت","تمازيغت"],"t":"الثقافة الأمازيغية","c":"الأمازيغ سكان المغرب الأصليون. لغتهم الأمازيغية. لها ثلاث لهجات: تشلحيت (سوس)، تريفيت (الريف)، تمازيغت (الأطلس). رأس السنة الأمازيغية يناير."},
            {"kw":["يناير","أمازيغي","سنة","13"],"t":"يناير (رأس السنة الأمازيغية)","c":"يناير رأس السنة الأمازيغية (13 يناير). عيد وطني في المغرب. يحتفل بالأكلات التقليدية."},
            {"kw":["مهرجان","مواسم","فن","موسم"],"t":"المهرجانات المغربية","c":"المغرب يعرف مهرجانات عالمية: موسم أصيلة الثقافي، مهرجان كناوة الصويرة، مهرجان مراكش الدولي للفيلم."},
            {"kw":["موسم","أصيلة","ثقافة","فنون"],"t":"موسم أصيلة","c":"موسم أصيلة الثقافي الدولي. ملتقى الفنانين والمثقفين. الجداريات في شوارع المدينة."},
            {"kw":["مسجد","حسن","ثاني","بيضا","صومعة"],"t":"المسجد الحسن الثاني","c":"المسجد الحسن الثاني في الدار البيضاء. ثاني أطول صومعة في العالم (210م). جزء منه على البحر. يسع 25 ألف مصل."},
            {"kw":["قرويين","جامعة","فاس","أقدم","فاطمة","فهرية"],"t":"جامعة القرويين","c":"جامعة القرويين في فاس. أقدم جامعة في العالم (859م). أسستها فاطمة الفهرية. موقع تراث عالمي لليونسكو."},
            {"kw":["فن","تشكيلي","مغربي","رسام"],"t":"الفن التشكيلي المغربي","c":"الفن التشكيلي المغربي غني. رواده: بن علي الرباطي، أحمد الشرقاوي، فريد بلكاهية."},

            # ═══════════════════════════════════════════
            #  الاقتصاد المغربي
            # ═══════════════════════════════════════════
            {"kw":["اقتصاد","مغربي","نمو","إنتاج"],"t":"الاقتصاد المغربي","c":"الاقتصاد المغربي متنوع. الفلاحة تشغل 30% من اليد العاملة. الصناعة: سيارات وطائرات. الفوسفاط (أول منتج عالمي). السياحة."},
            {"kw":["فوسفاط","منجم","OCP","مكتب","شريف"],"t":"الفوسفاط","c":"المغرب أول منتج للفوسفاط في العالم (70% من الاحتياطي العالمي). المكتب الشريف للفوسفاط (OCP) شركة عالمية."},
            {"kw":["سياحة","مغرب","زوار","فنادق","مليون"],"t":"السياحة في المغرب","c":"المغرب وجهة سياحية عالمية. مراكش، أكادير، طنجة، فاس أبرز الوجهات."},
            {"kw":["فلاحة","زراعة","مغرب","أخضر"],"t":"الفلاحة في المغرب","c":"الفلاحة تشغل 40% من المغاربة. المنتجات: الحبوب، الزيتون، الحمضيات، الطماطم، الأفوكادو. مخطط المغرب الأخضر."},
            {"kw":["صيد","بحر","سمك","مغرب","سردين"],"t":"الصيد البحري","c":"المغرب من أكبر منتجي السمك في إفريقيا. موانئ: أكادير، العيون، الداخلة، طنجة. السردين أول منتوج."},
            {"kw":["صناعة","سيارات","طائرات","مغرب","رونو"],"t":"الصناعة في المغرب","c":"المغرب أول منتج للسيارات في إفريقيا. مصانع رونو وستيلانتس في طنجة والدار البيضاء. صناعة الطائرات في النواصر."},
            {"kw":["مبادرة","تنمية","بشرية","INDH","محمد"],"t":"المبادرة الوطنية للتنمية البشرية","c":"المبادرة الوطنية للتنمية البشرية أطلقها الملك محمد السادس سنة 2005. تهدف لمحاربة الفقر والإقصاء الاجتماعي."},
            {"kw":["استثمار","أجنبي","مباشر","منطقة","حرة"],"t":"الاستثمار في المغرب","c":"المغرب يجذب الاستثمارات الأجنبية في الطاقة المتجددة والسيارات والطائرات. مناطق حرة في طنجة والنواصر."},
            {"kw":["طاقة","شمسية","ريحية","نظيفة","نور"],"t":"الطاقة المتجددة","c":"المغرب رائد في الطاقة المتجددة. مشروع نور ورزازات للطاقة الشمسية (أكبر محطة شمسية في العالم). مزارع الرياح في طنجة."},
            {"kw":["بنك","مال","درهم","مغربي","تجاري","وفا"],"t":"البنوك المغربية","c":"البنوك المغربية من أقوى في إفريقيا: التجاري وفا بنك، البنك الشعبي، BMCE بنك، بنك أفريقيا."},
            {"kw":["ميناء","طنجة","المتوسط","ميناء","بحر"],"t":"ميناء طنجة المتوسط","c":"ميناء طنجة المتوسط أكبر ميناء في إفريقيا. محطة للحاويات. يربط المغرب بأوروبا والعالم."},
            {"kw":["درهم","مغربي","عملة","صرف"],"t":"الدرهم المغربي","c":"الدرهم المغربي (MAD) العملة الرسمية. ينقسم إلى 100 سنتيم. سعر الصرف متقلب."},

            # ═══════════════════════════════════════════
            #  القانون المغربي — موسوعة قانونية شاملة
            # ═══════════════════════════════════════════
            {"kw":["قانون","مغربي","تشريع","نظام","قانوني"],"t":"النظام القانوني المغربي","c":"النظام القانوني المغربي نظام مختلط يجمع بين القانون المدني المتأثر بالنظام الفرنسي والشريعة الإسلامية. المصادر الرسمية: الدستور، القانون، العرف، الفقه الإسلامي."},
            {"kw":["دستور","2011","مغرب","إصلاح","دستوري"],"t":"دستور 2011","c":"دستور المغرب الحالي صدر في 1 يوليو 2011 بعد استفتاء شعبي. خصائصه: الأمازيغية لغة رسمية، المجلس الدستوري، استقلال القضاء، توسيع صلاحيات البرلمان والحكومة."},
            {"kw":["برلمان","نواب","مستشارين","تشريع","انتخاب"],"t":"البرلمان المغربي","c":"البرلمان المغربي غرفتان: مجلس النواب (395 عضوا ينتخبون مباشرة كل 5 سنوات) ومجلس المستشارين (120 عضوا). السلطة التشريعية."},
            {"kw":["انتخابات","مغرب","جماعية","تشريعية","مهنية"],"t":"الانتخابات في المغرب","c":"الانتخابات المغربية: تشريعية (مجلس النواب)، جماعية (الجماعات الترابية)، مهنية (الغرف المهنية). تشرف عليها وزارة الداخلية."},
            {"kw":["محكمة","قضاء","عدل","نقض","ابتدائية"],"t":"التنظيم القضائي المغربي","c":"التنظيم القضائي المغربي: محكمة النقض (أعلى هيئة)، محاكم الاستئناف، المحاكم الابتدائية، المحاكم الإدارية، المحاكم التجارية."},
            {"kw":["محكمة","نقض","تمييز","أعلى","هيئة"],"t":"محكمة النقض","c":"محكمة النقض أعلى هيئة قضائية في المغرب. مقرها الرباط. تنظر في الطعون بالنقض ضد أحكام محاكم الاستئناف."},
            {"kw":["محكمة","إدارية","قضاء","إداري","دعوى"],"t":"المحاكم الإدارية","c":"المحاكم الإدارية في المغرب تفصل في المنازعات بين المواطنين والإدارة. قراراتها قابلة للاستئناف أمام محاكم الاستئناف الإدارية."},
            {"kw":["محكمة","تجارية","قضاء","أعمال","شركات"],"t":"المحاكم التجارية","c":"المحاكم التجارية تفصل في المنازعات بين التجار والشركات والنزاعات المتعلقة بالأوراق التجارية."},
            {"kw":["قاضي","قضاء","سلطة","استقلال","مجلس"],"t":"القضاء في المغرب","c":"القضاء المغربي مستقل عن السلطتين التشريعية والتنفيذية. يديره المجلس الأعلى للسلطة القضائية. يرأسه الملك."},
            {"kw":["مجلس","سلطة","قضائية","أعلى","قاضي"],"t":"المجلس الأعلى للسلطة القضائية","c":"المجلس الأعلى للسلطة القضائية يرأسه الملك. يضمن استقلال القضاء. يعين القضاة ويأديبهم."},
            {"kw":["المحكمة","دستورية","محكمة","دستور","قانون"],"t":"المحكمة الدستورية","c":"المحكمة الدستورية تراقب دستورية القوانين. تفصل في الطعون الانتخابية. كانت تسمى المجلس الدستوري قبل دستور 2011."},
            {"kw":["مدونة","أسرة","مودة","زواج","طلاق","إرث"],"t":"مدونة الأسرة (المودة)","c":"مدونة الأسرة المغربية (المودة) صدرت 2004. تنظم: الزواج (الحد الأدنى 18 سنة)، الطلاق (الخلع والتفويت)، الإرث، النفقة، الحضانة. من أهم الإصلاحات."},
            {"kw":["زواج","عقد","مغرب","قانون","عائلي"],"t":"الزواج قانونا في المغرب","c":"الزواج في القانون المغربي عقد بين رجل وامرأة. السن القانوني: 18 سنة (باستثناءات بإذن القاضي). يشترط التوثيق في عدلين."},
            {"kw":["طلاق","خلع","تطليق","تفويت","مغرب"],"t":"الطلاق في المغرب","c":"أنواع الطلاق في مدونة الأسرة: الطلاق الاتفاقي، الطلاق بالخلع، الطلاق للتطليق، الطلاق بالتفويت. يتم أمام عدلين."},
            {"kw":["حضانة","أطفال","ولد","ولي","مغرب"],"t":"الحضانة في القانون المغربي","c":"الحضانة حق للطفل. الأم أولى بالحضانة حتى 18 سنة للذكور والإناث. النفقة واجبة على الأب. المحكمة تقرر المصلحة الفضلى."},
            {"kw":["إرث","ميراث","تركة","مواريث","مغرب"],"t":"الإرث في القانون المغربي","c":"الإرث في المغرب يحكمه قانون الأحوال الشخصية المستمد من الشريعة الإسلامية والفقه المالكي. الأنصبة محددة شرعا."},
            {"kw":["قانون","شغل","عمل","أجير","مستخدم"],"t":"قانون الشغل المغربي","c":"قانون الشغل المغربي (مدونة الشغل) صدر 2004. ينظم عقود العمل، الأجور (الحد الأدنى 3000 درهم شهريا)، الإجازات، إنهاء العلاقة الشغلية."},
            {"kw":["عقد","عمل","مغرب","مستخدم","أجير"],"t":"عقد العمل في المغرب","c":"عقد العمل في القانون المغربي: محدد المدة أو غير محدد المدة. الفترة التجريبية. ينتهي بالاستقالة أو الفصل أو انتهاء المدة."},
            {"kw":["فصل","طرد","مغرب","تعويض","محكمة"],"t":"الفصل التعسفي","c":"الفصل التعسفي في القانون المغربي هو الفصل دون سبب مشروع. يستحق العامل تعويضا يحدده القاضي. يحق للعامل الطعن أمام المحكمة."},
            {"kw":["إجازة","عطلة","سنوية","مرض","أمومة"],"t":"الإجازات في قانون الشغل المغربي","c":"الإجازات: سنوية (18 يوما بأجر)، مرضية، أمومة (14 أسبوعا)، ولادة (يومان للأب)، عيدية."},
            {"kw":["نقابة","عمال","اتحاد","مغرب"],"t":"النقابات العمالية في المغرب","c":"النقابات العمالية المغربية منظمة بموجب قانون الحريات النقابية. أبرزها: الاتحاد المغربي للشغل (UMT)، الاتحاد العام للشغالين بالمغرب (UGTM)."},
            {"kw":["قانون","جنائي","عقوبات","جريمة","مغرب"],"t":"القانون الجنائي المغربي","c":"القانون الجنائي المغربي (مجموعة القانون الجنائي) يحدد الجرائم والعقوبات. أنواع الجرائم: جنح، جنايات، مخالفات."},
            {"kw":["عقوبة","سجن","غرامة","إعدام","حبس"],"t":"العقوبات في القانون الجنائي المغربي","c":"العقوبات: السجن، الغرامة، العمل الاجتماعي. عقوبة الإعدام موجودة قانونا لكنها موقوفة (توقف التنفيذ منذ 1993)."},
            {"kw":["قانون","تجاري","أعمال","تاجر","شركة"],"t":"القانون التجاري المغربي","c":"القانون التجاري (مدونة التجارة) ينظم الأعمال التجارية والتجار والشركات والعقود التجارية والأوراق التجارية (الشيك، الكمبيالة)."},
            {"kw":["شركة","تأسيس","مسؤولية","محدودة","مغرب"],"t":"الشركات التجارية في المغرب","c":"أنواع الشركات: شركة المسؤولية المحدودة (SARL)، الشركة المجهولة الاسم (SA)، شركة التوصية البسيطة. الحد الأدنى لرأس المال يختلف."},
            {"kw":["قانون","ضريبة","جبايات","مغرب","ضرائب"],"t":"القانون الضريبي المغربي","c":"الضرائب المغربية: الضريبة على القيمة المضافة (TVA 20%)، الضريبة على الدخل (IR)، الضريبة على الشركات (IS). تديرها المديرية العامة للضرائب."},
            {"kw":["ضريبة","دخل","IR","أجير","مستقل"],"t":"الضريبة على الدخل (IR)","c":"الضريبة على الدخل في المغرب تصاعدية من 0% إلى 38%. تخص الأجور والأرباح المهنية والعقارية."},
            {"kw":["ضريبة","شركات","IS","مغرب"],"t":"الضريبة على الشركات (IS)","c":"الضريبة على الشركات في المغرب بنسبة 20% إلى 31% حسب نوع النشاط والربح."},
            {"kw":["قانون","عقاري","ملكية","عقار","أرض","مغرب"],"t":"القانون العقاري المغربي","c":"القانون العقاري المغربي ينظم الملكية العقارية. الحفاظ العقاري يسجل العقارات. أنواع الملكية: ملك خاص، ملك جماعي، ملك حبس."},
            {"kw":["عقار","شراء","بيع","سكن","مغرب"],"t":"شراء العقار في المغرب","c":"شراء العقار في المغرب: عقد البيع عند العدول أو المحامي، التسجيل في المحافظة العقارية، رسم التسجيل 5%."},
            {"kw":["كراء","إيجار","سكن","مغرب","قانون"],"t":"كراء العقار في المغرب","c":"كراء العقار في المغرب ينظمه قانون 67-12. العلاقة بين المالك والمستأجر. عقد الكراء يحدد المدة والواجبات."},
            {"kw":["جنسية","مغربية","إقامة","فيزا","تجنيس"],"t":"الجنسية والإقامة في المغرب","c":"الجنسية المغربية: بالولادة (أب مغربي)، بالزواج (بعد سنتين)، بالتجنيس (بقرار ملكي). الإقامة للأجانب: بطاقة الإقامة عبر العمل أو الاستثمار."},
            {"kw":["فيزا","مغرب","تأشيرة","دخول","أجنبي"],"t":"تأشيرة المغرب","c":"تأشيرة المغرب: عدة أنواع (سياحية، عمل، دراسة، لم الشمل). الإعفاء من التأشيرة لبعض الدول. تمنحها السفارات والقنصليات."},
            {"kw":["إقامة","أجنبي","مغرب","بطاقة","عمل"],"t":"بطاقة الإقامة للمغرب","c":"بطاقة الإقامة تمنح للأجانب. لم الشمل العائلي. الإقامة الدائمة بعد 5 سنوات من الإقامة المستمرة."},
            {"kw":["قانون","ملكية","فكرية","مؤلف","براءة","اختراع"],"t":"الملكية الفكرية في المغرب","c":"الملكية الفكرية في المغرب: المكتب المغربي للملكية الصناعية والتجارية (OMPIC) يدير براءات الاختراع والعلامات التجارية."},
            {"kw":["محامي","مهنة","قانون","نقابة","مغرب"],"t":"مهنة المحاماة في المغرب","c":"المحاماة في المغرب مهنة حرة. يشترط الإجازة في القانون والتدريب. نقابة المحامين تنظم المهنة."},
            {"kw":["عدول","توثيق","مغرب","قانون","عقد"],"t":"العدول في المغرب","c":"العدول موثقون تقليديون في المغرب. يوثقون عقود الزواج والطلاق والبيع بالطريقة الإسلامية. معترف بهم رسميا."},
            {"kw":["تحكيم","تجاري","مغرب","نزاع","اتفاق"],"t":"التحكيم التجاري في المغرب","c":"التحكيم التجاري وسيلة بديلة لحل النزاعات. مركز التحكيم التجاري بالدار البيضاء (CAC Mediation)."},
            {"kw":["قانون","مستهلك","حماية","مغرب","تجارة"],"t":"حماية المستهلك في المغرب","c":"قانون حماية المستهلك المغربي (القانون 31-08). يضمن حق المستهلك في السلامة والمعلومات والرجوع."},
            {"kw":["قانون","أسرة","نفقة","مغرب","حضانة"],"t":"النفقة في القانون المغربي","c":"النفقة واجبة على الأب تجاه أولاده وزوجته. تحددها المحكمة بنسبة مئوية من دخل الملزم."},
            {"kw":["زواج","قاصر","مغرب","قانون","قاضي"],"t":"زواج القاصر في المغرب","c":"زواج القاصر (تحت 18 سنة) مسموح بإذن قاضي. يجب تقديم مبررات قوية. الإحصاءات تظهر تراجع زواج القاصرات."},

            # ═══════════════════════════════════════════
            #  العادات والتقاليد
            # ═══════════════════════════════════════════
            {"kw":["رمضان","مغرب","صوم","فطور","تراويح"],"t":"رمضان في المغرب","c":"رمضان في المغرب يتميز بالحريرة والبريوات والبغرير. موائد الإفطار العائلية. صلاة التراويح في المساجد. الأجواء الروحانية."},
